            width: 36,
            height: 36,
            borderRadius: 8,
            background: "linear-gradient(135deg, #F59E0B, #FBBF24)",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontWeight: 800,
            fontSize: 15,
            color: "#fff",
            flexShrink: 0,
            letterSpacing: "-0.5px",
          }}
        >
          PA
        </div>
        {!collapsed && (
          <div>
            <div
              style={{
                fontWeight: 800,
                fontSize: 16,
                color: "#1F2937",
                letterSpacing: "0.5px",
                lineHeight: 1.2,
