          </div>
        )}
      </div>

      {/* Menu */}
      <div style={{ flex: 1, overflowY: "auto", overflowX: "hidden", padding: "12px 0" }}>
        {menuGroups.map((group) => (
          <div key={group.title} style={{ marginBottom: "20px" }}>
            {!collapsed && (
              <div
