                color: "#EF4444",
                cursor: "pointer",
                fontSize: 13,
                fontWeight: 500,
              }}
            >
              <AiOutlineLogout style={{ fontSize: 16 }} />
              <span>Logout Account</span>
            </div>
          </>
        )}
      </div>
