/* ============================================
   PHÚC AN Dashboard Styles
   ============================================ */

/* Background page */
body {
  background-color: #F5F6F8;
}

/* ============================================
   TOP BAR
   ============================================ */
.top-bar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  width: 100%;
  margin-bottom: 0;
  padding: 0;
  background: transparent;
}

.top-bar-left {
  flex: 1;
}

.top-bar-center {
  flex: 1;
  display: flex;
  justify-content: center;
  max-width: 480px;
  margin: 0 auto;
}

.top-bar-search {
  display: flex;
  align-items: center;
  gap: 8px;
  background: #F3F4F6;
  border-radius: 9999px;
  padding: 8px 16px;
  width: 100%;
  max-width: 400px;
}

.top-bar-search-icon {
  color: #9CA3AF;
  font-size: 16px;
  flex-shrink: 0;
}

.top-bar-search-input {
  border: none;
  background: transparent;
  outline: none;
  font-size: 14px;
  color: #374151;
  width: 100%;
  padding: 0;
}

.top-bar-search-input::placeholder {
  color: #9CA3AF;
}

.top-bar-right {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: flex-end;
  gap: 14px;
  padding-right: 4px;
}

.top-bar-bell {
  font-size: 20px;
  color: #6B7280;
  cursor: pointer;
}

/* ============================================
   DASHBOARD CONTENT HEADER
   ============================================ */
.dashboard-content-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding-bottom: 24px;
  margin-bottom: 0;
  /* no extra background/border — just layout */
}

.dashboard-content-title {
  font-size: 26px;
  font-weight: 700;
  color: #1F2937;
  margin: 0;
  letter-spacing: -0.5px;
  white-space: nowrap;
  flex-shrink: 0;
}

.dashboard-content-controls {
  display: flex;
  align-items: center;
  gap: 12px;
  flex-wrap: wrap;
}

/* Export icon button */
.export-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 38px;
  height: 38px;
  border-radius: 8px;
  background: #EFF6FF;
  border: 1px solid #DBEAFE;
  color: #1D4ED8;
  cursor: pointer;
  font-size: 18px;
  transition: all 0.15s ease;
  padding: 0;
}

.export-btn:hover {
  background: #DBEAFE;
  border-color: #BFDBFE;
  transform: translateY(-1px);
}

.export-btn:active {
  transform: translateY(0);
}

